import { saveAs } from 'file-saver';
import Button from 'flarum/common/components/Button';
import app from 'flarum/common/app';
import Component from 'flarum/common/Component';
import CustomEmojiList from './CustomEmojiList';
import EditEmojiModal from './EditEmojiModal';
import listItems from 'flarum/common/helpers/listItems';
import ItemList from 'flarum/common/utils/ItemList';
export default class CustomEmojiSection extends Component {
  oninit(vnode) {
    super.oninit(vnode);
  }
  exportEmojiList() {
    var customEmojiList = {};
    app.request({
      method: 'GET',
      url: `${app.forum.attribute('apiUrl')}/flamojis/all`
    }).then(response => {
      const emojis = Object.keys(response).filter(k => !isNaN(k)).map(k => response[k]);
      emojis.map((emoji, i) => {
        customEmojiList[i] = {
          title: emoji.title,
          text_to_replace: emoji.text_to_replace,
          path: emoji.path
        };
      });
      var blob = new Blob([JSON.stringify(customEmojiList)], {
        type: 'application/json;charset=utf-8'
      });
      saveAs(blob, 'flamoji.json');
    });
  }
  importEmojiList() {
    if (!confirm(app.translator.trans('pianotell-flamoji.admin.custom_emojis_section.import_emojis_message', {}, true))) return;
    var input = document.createElement('input');
    input.type = 'file';
    input.onchange = e => {
      app.customEmojiListState.loading = true;

      // getting a hold of the file reference
      var file = e.target.files[0];

      // setting up the reader
      var reader = new FileReader();
      reader.readAsText(file, 'UTF-8');

      // here we tell the reader what to do when it's done reading...
      reader.onload = readerEvent => {
        app.request({
          method: 'POST',
          url: `${app.forum.attribute('apiUrl')}/flamojis/import`,
          body: {
            data: JSON.parse(readerEvent.target.result)
          }
        }).then(() => {
          EditEmojiModal.prototype.clearCache().then(() => window.location.reload());
        });
      };
    };
    input.click();
  }
  flamojiTopItems() {
    const items = new ItemList();
    items.add('import', m(Button, {
      icon: "fas fa-sign-in-alt",
      onclick: () => this.importEmojiList()
    }, app.translator.trans('pianotell-flamoji.admin.custom_emojis_section.import_json_button')));
    items.add('export', m(Button, {
      icon: "fas fa-share",
      onclick: () => this.exportEmojiList()
    }, app.translator.trans('pianotell-flamoji.admin.custom_emojis_section.export_json_button')));
    return items;
  }
  view() {
    return m("div", {
      className: "ExtensionPage-customFlamoji"
    }, m("div", {
      className: "ExtensionPage-customFlamoji-header"
    }, m("div", {
      className: "container"
    }, m("div", {
      className: "ExtensionTitle"
    }, m("div", {
      className: "ExtensionName"
    }, m("h2", null, app.translator.trans('pianotell-flamoji.admin.custom_emojis_section.heading_title'))), m("div", {
      class: "ExtensionPage-headerTopItems"
    }, m("ul", null, listItems(this.flamojiTopItems().toArray())))))), m("div", {
      className: "container"
    }, m(CustomEmojiList, null)));
  }
}
flarum.reg.add('pianotell-flamoji', 'admin/components/CustomEmojiSection', CustomEmojiSection);